-- Seed 2025: данные из управленческой таблицы (синтетика).
-- • pnl_monthly_values: revenue, gross_margin.
-- • expenses: по одному агрегату на категорию и месяц (дата 15-е число UTC), чтобы помесячный P&L совпадал с исходом;
--   «Прибыль убыток» 308 608 в декабре — как расход (см. строку SYN-2025-profit-loss-dec).
-- • ИТОГО выручка/маржа сверены с колонкой «ИТОГО» (декабрь скорректирован на +3 ₽ / +1 ₽ из‑за округлений в помесячных суммах).
-- • Пропущены нулевые категории: Колл-центр, Бухгалтерия, Разработка IT; строки-итоги («Расходы в 1с» и т.д.) не вносятся.

on conflict (year, month, metric) do update set amount = excluded.amount, updated_at = now();

on conflict (external_number) do update set
  document_title = excluded.document_title,
  expense_date   = excluded.expense_date,
  contractor     = excluded.contractor,
  comment        = excluded.comment,
  amount         = excluded.amount,
  category       = excluded.category,
  source         = excluded.source,
  deleted_at     = null,
  deleted_reason = null,
  updated_at     = now();
